#include <iostream>
#include <vector>
#include <algorithm>
#include <sstream>
using namespace std;

int main() {
    string line1, line2;
    vector<int> a, b, res;
    if (getline(cin, line1) && getline(cin, line2)) {
        if (line1 != "empty") { stringstream ss(line1); int v; while(ss>>v) a.push_back(v); }
        if (line2 != "empty") { stringstream ss(line2); int v; while(ss>>v) b.push_back(v); }
    }
    merge(a.begin(),a.end(),b.begin(),b.end(),back_inserter(res));
    if (res.empty()) cout << "empty"; else for(int i=0;i<res.size();i++){if(i)cout<<' ';cout<<res[i];}
    cout << endl;
    return 0;
}

