public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        ArrayList<Integer> a = new ArrayList<>(), b = new ArrayList<>();
        if (sc.hasNextLine()) {
            String l = sc.nextLine().trim();
            if (!l.equals("empty")) for (String s : l.split("\\s+")) a.add(Integer.parseInt(s));
        }
        if (sc.hasNextLine()) {
            String l = sc.nextLine().trim();
            if (!l.equals("empty")) for (String s : l.split("\\s+")) b.add(Integer.parseInt(s));
        }
        ArrayList<Integer> res = new ArrayList<>(a); res.addAll(b); Collections.sort(res);
        if (res.isEmpty()) System.out.println("empty");
        else { StringBuilder sb = new StringBuilder(); for (int i=0;i<res.size();i++){if(i>0)sb.append(' ');sb.append(res.get(i));} System.out.println(sb); }
    }
}

