#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int cmp(const void*a,const void*b){return *(int*)a-*(int*)b;}
int main() {
    int arr[200], n=0;
    char buf[1024];
    for(int l=0;l<2;l++) {
        if(!fgets(buf,sizeof(buf),stdin)) break;
        buf[strcspn(buf,"\n")]=0;
        if(strcmp(buf,"empty")==0) continue;
        char*tok=strtok(buf," ");
        while(tok){arr[n++]=atoi(tok);tok=strtok(NULL," ");}
    }
    if(n==0){printf("empty\n");return 0;}
    qsort(arr,n,sizeof(int),cmp);
    for(int i=0;i<n;i++){if(i)printf(" ");printf("%d",arr[i]);}printf("\n");
    return 0;
}
